{"nbformat":4,"nbformat_minor":0,"metadata":{"colab":{"provenance":[],"authorship_tag":"ABX9TyPCobswY0dGjFVT4sRhbanN"},"kernelspec":{"name":"python3","display_name":"Python 3"},"language_info":{"name":"python"}},"cells":[{"cell_type":"code","execution_count":null,"metadata":{"id":"-Fsqc9LiDCfd"},"outputs":[],"source":["# run_prediction.py\n","import pandas as pd\n","import numpy as np\n","import joblib\n","import logging\n","from datetime import datetime, timedelta\n","import os\n","\n","# Configuration Logging (Pour tracer les erreurs en prod)\n","logging.basicConfig(filename='prediction_log.log', level=logging.INFO)\n","\n","def load_production_model(path='model_production.pkl'):\n","    \"\"\"Charge le modèle et vérifie sa validité\"\"\"\n","    try:\n","        package = joblib.load(path)\n","        logging.info(f\"Modèle chargé : {package['model_type']} (v{package['version']})\")\n","        return package\n","    except Exception as e:\n","        logging.error(f\"Erreur chargement modèle : {e}\")\n","        raise\n","\n","def prepare_features_for_tomorrow(historical_data, tomorrow_date):\n","    \"\"\"\n","    RECONSTRUIT les features exactement comme à l'entraînement\n","    C'est l'étape la plus critique !\n","    \"\"\"\n","    # 1. Filtrer les données jusqu'à hier (on ne connait pas demain)\n","    yesterday = tomorrow_date - timedelta(days=1)\n","    df = historical_data[historical_data['date'] <= yesterday].copy()\n","\n","    # 2. Appliquer la même logique de Feature Engineering\n","    # (Tu dois copier-coller tes fonctions de création de lags/rolling ici)\n","    # Exemple simplifié :\n","    df['lag_7'] = df['sales'].shift(7)\n","    df['rolling_mean_7'] = df['sales'].rolling(7).mean()\n","    # ... ajouter toutes les autres features ...\n","\n","    # 3. Sélectionner uniquement la ligne de \"demain\" (les features sont prêtes)\n","    # Les features de la ligne N utilisent les données de N-1, N-7, etc.\n","    # Donc on prend la dernière ligne disponible après calcul\n","    last_row = df.iloc[[-1]][package['feature_names']]\n","\n","    return last_row\n","\n","def main():\n","    logging.info(\"=== Démarrage Pipeline Prédiction ===\")\n","\n","    # 1. Charger le modèle\n","    package = load_production_model()\n","    model = package['model']\n","    features_required = package['feature_names']\n","\n","    # 2. Récupérer les données fraîches (Depuis SQL / ERP / CSV)\n","    # historical_data = pd.read_sql(\"SELECT * FROM sales_history\", db_connection)\n","    historical_data = pd.read_csv('data/sales_history_updated.csv')\n","\n","    # 3. Préparer les features pour demain\n","    tomorrow = datetime.now() + timedelta(days=1)\n","    X_tomorrow = prepare_features_for_tomorrow(historical_data, tomorrow)\n","\n","    # 4. Prédire\n","    try:\n","        prediction = model.predict(X_tomorrow)[0]\n","        logging.info(f\"Prédiction pour {tomorrow.date()} : {prediction:.2f}\")\n","\n","        # 5. Sauvegarder le résultat (Pour Power BI ou ERP)\n","        result_df = pd.DataFrame({\n","            'date': [tomorrow],\n","            'store_id': [1],\n","            'predicted_sales': [prediction],\n","            'model_version': [package['version']],\n","            'generated_at': [datetime.now()]\n","        })\n","\n","        # Append au fichier de résultats\n","        if os.path.exists('predictions_output.csv'):\n","            result_df.to_csv('predictions_output.csv', mode='a', header=False, index=False)\n","        else:\n","            result_df.to_csv('predictions_output.csv', index=False)\n","\n","        logging.info(\"✅ Prédiction sauvegardée avec succès\")\n","\n","    except Exception as e:\n","        logging.error(f\"❌ Erreur lors de la prédiction : {e}\")\n","\n","if __name__ == \"__main__\":\n","    main()"]}]}